import { Component, input, output, computed } from '@angular/core';
import { CommonModule } from '@angular/common';

export type ButtonVariant = 'default' | 'secondary' | 'outline' | 'ghost' | 'destructive';
export type ButtonSize = 'sm' | 'md' | 'lg' | 'icon';
export type ButtonType = 'button' | 'submit' | 'reset';

@Component({
  selector: 'app-button',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './button.component.html',
  styleUrl: './button.component.scss',
})
export class ButtonComponent {
  variant = input<ButtonVariant>('default');
  size = input<ButtonSize>('md');
  disabled = input<boolean>(false);
  loading = input<boolean>(false);
  type = input<ButtonType>('button');

  clicked = output<MouseEvent>();

  isDisabled = computed(() => this.disabled() || this.loading());

  hostClasses = computed(() => {
    return [
      'btn',
      `btn--${this.variant()}`,
      `btn--${this.size()}`,
      this.isDisabled() ? 'btn--disabled' : '',
      this.loading() ? 'btn--loading' : '',
    ]
      .filter(Boolean)
      .join(' ');
  });

  onClick(event: MouseEvent): void {
    if (!this.isDisabled()) {
      event.stopPropagation();
      this.clicked.emit(event);
    }
  }
}

import { Component, computed, contentChild, input, output } from '@angular/core';
import { NgClass } from '@angular/common';
import { CardHeaderDirective } from './card-header.directive';
import { CardFooterDirective } from './card-footer.directive';

export type CardVariant = 'default' | 'interactive' | 'selected';
export type CardPadding = 'none' | 'sm' | 'md' | 'lg';

@Component({
  selector: 'app-card',
  standalone: true,
  imports: [NgClass],
  templateUrl: './card.component.html',
  styleUrl: './card.component.scss',
})
export class CardComponent {
  variant = input<CardVariant>('default');
  padding = input<CardPadding>('md');

  cardClick = output<void>();

  headerContent = contentChild(CardHeaderDirective);
  footerContent = contentChild(CardFooterDirective);


  hasHeader = computed(() => !!this.headerContent());
  hasFooter = computed(() => !!this.footerContent());

  classes = computed(() => ({
    card: true,
    [`card--${this.variant()}`]: true,
    [`card--padding-${this.padding()}`]: true,
  }));

  onClick(): void {
    if (this.variant() === 'interactive') {
      this.cardClick.emit();
    }
  }
}

import { CommonModule } from '@angular/common';
import { Component, computed, effect, input, model, signal } from '@angular/core';
import {
  Check,
  LUCIDE_ICONS,
  LucideAngularModule,
  LucideIconProvider,
  Minus,
} from 'lucide-angular';

@Component({
  selector: 'app-checkbox',
  standalone: true,
  imports: [CommonModule, LucideAngularModule],
  providers: [
    {
      provide: LUCIDE_ICONS,
      useValue: new LucideIconProvider({ Check, Minus }),
      multi: true,
    },
  ],
  templateUrl: './checkbox.component.html',
  styleUrl: './checkbox.component.scss',
})
export class CheckboxComponent {
  private static idCounter = 0;
  readonly inputId = `app-checkbox-${++CheckboxComponent.idCounter}`;
  checked = model<boolean>(false);
  label = input<string>('');
  description = input<string>('');
  disabled = input<boolean>(false);
  indeterminate = input<boolean>(false);
  error = input<string>('');

  isIndeterminate = signal(false);

  hasLabel = computed(() => this.label().length > 0);
  hasDescription = computed(() => this.description().length > 0);
  hasError = computed(() => this.error().length > 0);

  constructor() {
    effect(() => {
      this.isIndeterminate.set(this.indeterminate());
    });
  }

  toggle(): void {
    if (this.disabled()) return;

    if (this.isIndeterminate()) {
      this.isIndeterminate.set(false);
      this.checked.set(true);
      return;
    }

    this.checked.update((value) => !value);
  }

  onKeydown(event: KeyboardEvent): void {
    if (event.code === 'Space') {
      event.preventDefault();
      this.toggle();
    }
  }
}

