@if (hasLabel()) {
  <label class="pw-input__label" [for]="inputId">
    {{ label() }}
    @if (required()) {
      <span class="pw-input__required" aria-hidden="true">*</span>
    }
  </label>
}

<div class="pw-input__wrapper" [class.pw-input__wrapper--error]="hasError()" [class.pw-input__wrapper--disabled]="disabled()">
  <input
    class="pw-input__field"
    [id]="inputId"
    [type]="showPassword() ? 'text' : 'password'"
    [placeholder]="placeholder()"
    [attr.disabled]="disabled() ? '' : null"
    [attr.required]="required() ? '' : null"
    [value]="value()"
    (input)="onInput($event)"
    (focus)="onFocus()"
    (blur)="onBlur()"
  />
  <button
    type="button"
    class="pw-input__toggle"
    [attr.disabled]="disabled() ? '' : null"
    (click)="toggleVisibility()"
    [attr.aria-label]="showPassword() ? 'Ocultar senha' : 'Mostrar senha'"
    [attr.aria-pressed]="showPassword()"
  >
    @if (showPassword()) {
      <lucide-angular name="eye-off" [size]="16" [strokeWidth]="1.75" />
    } @else {
      <lucide-angular name="eye" [size]="16" [strokeWidth]="1.75" />
    }
  </button>
</div>

@if (hasError()) {
  <span class="pw-input__error" role="alert">{{ error() }}</span>
}

@if (showStrength()) {
  <div class="pw-input__strength">
    <div class="pw-input__bars">
      @for (i of [0, 1, 2]; track i) {
        <span
          class="pw-input__bar"
          [class.pw-input__bar--filled]="filledSegments() > i"
          [attr.data-strength]="filledSegments() > i ? strength() : null"
        ></span>
      }
    </div>
    @if (strengthLabel()) {
      <span class="pw-input__strength-label" [attr.data-strength]="strength()">
        {{ strengthLabel() }}
      </span>
    }
  </div>

  @if (showCriteria()) {
    <ul class="pw-input__criteria">
      <li class="pw-input__criterion" [class.pw-input__criterion--met]="criteria().length">
        <lucide-angular
          [name]="criteria().length ? 'check' : 'x'"
          [size]="12"
          [strokeWidth]="2"
        />
        <span>Mínimo de {{ minLength() }} caracteres</span>
      </li>
      <li class="pw-input__criterion" [class.pw-input__criterion--met]="criteria().uppercase">
        <lucide-angular
          [name]="criteria().uppercase ? 'check' : 'x'"
          [size]="12"
          [strokeWidth]="2"
        />
        <span>Uma letra maiúscula</span>
      </li>
      <li class="pw-input__criterion" [class.pw-input__criterion--met]="criteria().number">
        <lucide-angular
          [name]="criteria().number ? 'check' : 'x'"
          [size]="12"
          [strokeWidth]="2"
        />
        <span>Um número</span>
      </li>
      <li class="pw-input__criterion" [class.pw-input__criterion--met]="criteria().special">
        <lucide-angular
          [name]="criteria().special ? 'check' : 'x'"
          [size]="12"
          [strokeWidth]="2"
        />
        <span>Um caractere especial</span>
      </li>
    </ul>
  }
}

