@if (mobileOpen()) {
  <div class="sidebar__overlay" (click)="closeMobile()" aria-hidden="true"></div>
}

<aside
  class="sidebar"
  [class.sidebar--collapsed]="collapsed()"
  [class.sidebar--mobile-open]="mobileOpen()"
  aria-label="Navegação principal"
>
  <div class="sidebar__header">
    <div class="sidebar__logo">
      <ng-content select="[sidebar-logo]" />
    </div>
    <button
      class="sidebar__toggle"
      type="button"
      [attr.aria-label]="collapsed() ? 'Expandir menu' : 'Colapsar menu'"
      (click)="toggleCollapsed()"
    >
      @if (collapsed()) {
        <lucide-angular name="panel-left-open" [size]="20" [strokeWidth]="1.75" />
      } @else {
        <lucide-angular name="panel-left-close" [size]="20" [strokeWidth]="1.75" />
      }
    </button>
  </div>

  <nav class="sidebar__nav" aria-label="Menu principal">
    <ul class="sidebar__list" role="list">
      @for (item of items(); track trackByRoute($index, item)) {
        @if (item.isHeader) {
          <li class="sidebar__section-title" [class.sidebar__section-title--collapsed]="collapsed()" aria-hidden="true">
            @if (!collapsed()) {
              <span>{{ item.label }}</span>
            } @else {
              <hr class="sidebar__divider" />
            }
          </li>
        } @else {
          <li>
            <button
              class="sidebar__item"
              [class.sidebar__item--active]="isActive(item.route)"
              type="button"
              [attr.title]="collapsed() ? item.label : null"
              (click)="onItemClick(item)"
            >
              <span class="sidebar__icon-wrapper">
                <lucide-angular
                  [name]="item.icon"
                  [size]="20"
                  [strokeWidth]="1.75"
                  class="sidebar__icon"
                />
                @if (item.badge) {
                  <span class="sidebar__badge-dot" aria-hidden="true"></span>
                }
              </span>
              @if (!collapsed()) {
                <span class="sidebar__label">{{ item.label }}</span>
              }
              @if (item.badge && !collapsed()) {
                <span class="sidebar__badge" [attr.aria-label]="item.badge + ' notificações'">
                  {{ item.badge }}
                </span>
              }
            </button>
          </li>
        }
      }
    </ul>
  </nav>

  <div class="sidebar__footer">
    <ng-content select="[sidebar-footer]" />
  </div>
</aside>

